import {
  Body,
  Controller,
  Param,
  Patch,
  Post,
  UploadedFile,
  UseInterceptors,
} from '@nestjs/common';
import { FileInterceptor } from '@nestjs/platform-express';
import { Uuid } from '@/app/common/utils/uuid.util';

/**
 * Stub controller for testing video analysis endpoints
 * This controller simulates the external analysis server for local testing
 */
@Controller('api/stub')
export class StubController {
  /**
   * POST /api/stub/analyze/
   * Simulates video upload and analysis initiation
   */
  @Post('analyze')
  @UseInterceptors(FileInterceptor('file'))
  async analyzeVideo(
    @UploadedFile() file: Express.Multer.File,
    @Body() body: any,
  ): Promise<{ id: string }> {
    // Generate a mock resource ID
    const resourceId = body.resource_id || Uuid.v4();

    return {
      id: resourceId,
    };
  }

  /**
   * PATCH /api/stub/analyze/:resourceId
   * Simulates re-analysis of an existing video
   */
  @Patch('analyze/:resourceId')
  async reanalyzeVideo(
    @Param('resourceId') resourceId: string,
    @Body() body: any,
  ): Promise<void> {
    // Simply return success for stub
    return;
  }
}

