import { HttpModule } from '@nestjs/axios';
import { CacheModule } from '@nestjs/cache-manager';
import { MiddlewareConsumer, Module } from '@nestjs/common';
import { APP_FILTER } from '@nestjs/core';
import { MulterModule } from '@nestjs/platform-express';
import { TypeOrmModule } from '@nestjs/typeorm';

import { AppConstants } from '@/app/common/constants/app.constants';
import {
  authorizedControllers,
  authorizedForInternalControllers,
  persistences,
  services,
} from '@/app/common/decorators';
import { AiCoachReportsController } from '@/app/controllers/api/ai-coach-reports.controller';
import { AuthController } from '@/app/controllers/api/auth.controller';
import { BatchProcessingController } from '@/app/controllers/api/batch-processing.controller';
import { InternalIFController } from '@/app/controllers/api/internal-if.controller';
import { ItemsController } from '@/app/controllers/api/masters/items.controller';
import { MastersController } from '@/app/controllers/api/masters/masters.controller';
import { PlansController } from '@/app/controllers/api/masters/plans.controller';
import { SubscriptionsController } from '@/app/controllers/api/masters/subscriptions.controller';
import { NotificationsController } from '@/app/controllers/api/notifications.controller';
import { SamplesController } from '@/app/controllers/api/samples.controller';
import { TeamAdminsController } from '@/app/controllers/api/teams/team-admins.controller';
import { TeamAiCoachReportsController } from '@/app/controllers/api/teams/team-ai-coach-reports.controller';
import { TeamBallsController } from '@/app/controllers/api/teams/team-balls.controller';
import { TeamPaymentSessionsController } from '@/app/controllers/api/teams/team-payment-sessions.controller';
import { TeamPlansController } from '@/app/controllers/api/teams/team-plans.controller';
import { TeamPlayersController } from '@/app/controllers/api/teams/team-players.controller';
import { TeamResourcesController } from '@/app/controllers/api/teams/team-resources.controller';
import { TeamSessionsController } from '@/app/controllers/api/teams/team-sessions.controller';
import { TeamUsersController } from '@/app/controllers/api/teams/team-users.controller';
import { TeamsController } from '@/app/controllers/api/teams/teams.controller';
import { UsersController } from '@/app/controllers/api/users/users.controller';
import { CodedExceptionHandler } from '@/app/exceptions/handlers/coded.handlers';
import { ExceptionHandler } from '@/app/exceptions/handlers/handler';
import { ValidationExceptionHandler } from '@/app/exceptions/handlers/validation.exception.handler';
import { AiCoachReportsListener } from '@/app/listeners/ai-coach-reports.listener';
import { AuthMiddleware } from '@/app/middlewares/auth.middleware';
import { CommonMiddleware } from '@/app/middlewares/common.middleware';
import { CorsMiddleware } from '@/app/middlewares/cors.middleware';
import { InternalAuthMiddleware } from '@/app/middlewares/internal-auth.middleware';
import { ALL_MODELS } from '@/app/models';
import { AnalysisProvider } from '@/app/providers/analysis.provider';
import { AppleProvider } from '@/app/providers/apple.provider';
import { CognitoProvider } from '@/app/providers/cognito.provider';
import { ConfigProvider } from '@/app/providers/config.provider';
import { EmailProvider } from '@/app/providers/email.provider';
import { I18nProvider } from '@/app/providers/i18n.provider';
import { LlmProvider } from '@/app/providers/llm.provider';
import { SlackProvider } from '@/app/providers/slack.provider';
import { StorageProvider } from '@/app/providers/storage.provider';
import { StripeProvider } from '@/app/providers/stripe.provider';

const allControllers = [
  SamplesController,

  AiCoachReportsController,
  AuthController,
  BatchProcessingController,
  InternalIFController,
  ItemsController,
  MastersController,
  NotificationsController,
  PlansController,
  SubscriptionsController,
  TeamAdminsController,
  TeamAiCoachReportsController,
  TeamBallsController,
  TeamPaymentSessionsController,
  TeamPlansController,
  TeamPlayersController,
  TeamResourcesController,
  TeamSessionsController,
  TeamUsersController,
  TeamsController,
  UsersController,
];

const providers = [
  AnalysisProvider,
  AppleProvider,
  CognitoProvider,
  ConfigProvider,
  EmailProvider,
  I18nProvider,
  SlackProvider,
  LlmProvider,
  StorageProvider,
  StripeProvider,
];

const nestServices = [...services, ...persistences, ...providers];

@Module({
  controllers: allControllers,
  imports: [
    HttpModule.registerAsync({
      useFactory: () => ({
        timeout: 300 * 1000,
      }),
    }),
    CacheModule.register(),
    MulterModule.registerAsync({
      useFactory: () => ({
        dest: '/tmp/upload',
        limits: {
          fileSize: AppConstants.global_file_size_limitation,
        },
      }),
    }),
    TypeOrmModule.forFeature(ALL_MODELS),
  ],
  providers: [
    {
      provide: APP_FILTER,
      useClass: ExceptionHandler,
    },
    {
      provide: APP_FILTER,
      useClass: CodedExceptionHandler,
    },
    {
      provide: APP_FILTER,
      useClass: ValidationExceptionHandler,
    },
    ...nestServices,
    AiCoachReportsListener,
  ],
})
export class ApiModule {
  configure(consumer: MiddlewareConsumer) {
    consumer.apply(CommonMiddleware).forRoutes('*');
    consumer.apply(CorsMiddleware).forRoutes('*');
    consumer.apply(AuthMiddleware).forRoutes(...authorizedControllers);
    consumer
      .apply(InternalAuthMiddleware)
      .forRoutes(...authorizedForInternalControllers);
  }
}

