@UseGuards(new TeamAccessGuard('basic', 'write'))
@CodedMethod('UTSS')
@Put(':sessionId')
async updateTeamSession(
  @Req() req: AppExtendedRequest,
  @Param('teamId', ParseUUIDPipe) targetTeamId: string,
  @Param('sessionId', ParseUUIDPipe) sessionId: string,
  @Body() dto: SessionUpdateDto,
) {
  const cbuilder = this.getCodeBuilder();
  const { requesterUid, roleChecker } = req.appExtension.auth!;

  // The accessibility to the team already checked by TeamAccessGuard.
  const cannotAccessTeammatesData = !roleChecker.check(
    targetTeamId,
    'basic',
    'write',
    true,
  );

  const validated = ValidationUtil.validate(sessionUpdateDtoValidator(), dto);

  const { session } = await this.sessionsService.updateSession(
    targetTeamId,
    sessionId,
    validated,
    cannotAccessTeammatesData ? { userId: requesterUid } : {},
  );

