/// Ensure that all player pages are loaded into the current state.
Future<PagingData<Player>> ensureAllPlayersLoaded({
  int? batchSize,
}) async {
  final resolvedPageSize = batchSize ?? _ensureAllPlayersPageSize;

  // Wait for initial load to complete if currently loading
  if (state.isLoading) {
    // Poll until loading is complete
    var attempts = 0;
    const maxAttempts = 600; // 60 seconds timeout
    while (state.isLoading && attempts < maxAttempts) {
      await Future.delayed(const Duration(milliseconds: 100));
      attempts++;
    }

    if (state.isLoading) {
      throw StateError('Timeout waiting for player list to load');
    }
  }

  // If state is still null after waiting, initialize with first page
  if (state.value == null) {
    await loadNext(pageSize: resolvedPageSize);
    if (state.value == null) {
      throw StateError('Failed to load initial player data');
    }
  }

  final current = state.value!;
  return _drainRemainingPages(current, resolvedPageSize);
}

